import{_ as a,o as t,c as r,ag as i}from"./chunks/framework.DXGyWiRo.js";const m=JSON.parse('{"title":"Practical (Paper 1)","description":"","frontmatter":{"title":"Practical (Paper 1)","nav_order":3,"has_children":true},"headers":[],"relativePath":"practical/index.md","filePath":"practical/index.md"}'),s={name:"practical/index.md"};function o(n,e,l,c,d,p){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="practical-—-paper-1-overview" tabindex="-1">Practical — Paper 1 Overview <a class="header-anchor" href="#practical-—-paper-1-overview" aria-label="Permalink to &quot;Practical — Paper 1 Overview&quot;">​</a></h1><p>Paper 1 is the <strong>computer-based practical examination</strong> for Information Technology. You will have access to a computer and will write real Delphi code, run SQL queries, and solve problems using the skills you have developed during the year.</p><p>This section of IT Gateway covers everything you need for Paper 1, organised by topic: algorithms and problem-solving, Delphi programming, SQL database queries, and number systems.</p><h2 id="what-s-in-this-section" tabindex="-1">What&#39;s in this section <a class="header-anchor" href="#what-s-in-this-section" aria-label="Permalink to &quot;What&#39;s in this section&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Topic</th><th>What you&#39;ll learn</th></tr></thead><tbody><tr><td><a href="./algorithms/">Algorithms</a></td><td>Designing solutions using flowcharts, pseudocode, sequential, decision and repetition structures</td></tr><tr><td><a href="./delphi/">Delphi Programming</a></td><td>Delphi IDE, components, variables, operators, selection, loops, arrays, strings, files and OOP</td></tr><tr><td><a href="./sql/">SQL</a></td><td>SELECT queries, filtering, sorting, joins, aggregate functions, DML and DDL</td></tr><tr><td><a href="./number-systems/">Number Systems</a></td><td>Binary, hexadecimal, conversions, arithmetic and data size calculations</td></tr></tbody></table><h2 id="how-paper-1-works" tabindex="-1">How Paper 1 works <a class="header-anchor" href="#how-paper-1-works" aria-label="Permalink to &quot;How Paper 1 works&quot;">​</a></h2><ul><li>The exam is done on a <strong>computer</strong> supplied by the school or examination centre.</li><li>You will receive a <strong>question paper</strong> and a <strong>data folder</strong> containing Delphi project files and database files.</li><li>Answers are submitted as <strong>saved files</strong> — make sure you save frequently!</li><li>The exam is <strong>3 hours</strong> long.</li><li>Typical mark split: Delphi ~60%, SQL ~20%, Algorithms/Number systems ~20% (varies per year).</li></ul><h2 id="caps-alignment" tabindex="-1">CAPS alignment <a class="header-anchor" href="#caps-alignment" aria-label="Permalink to &quot;CAPS alignment&quot;">​</a></h2><p>Paper 1 assesses the <strong>Solution Development</strong> and <strong>Data &amp; Information Management</strong> (practical SQL) components of CAPS across Grades 10, 11 and 12. The complexity of questions increases each year.</p>',9)])])}const u=a(s,[["render",o]]);export{m as __pageData,u as default};
